const input = $input.first().json;
const action = input.action || 'list_accounts';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

// Load credentials
const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.kontoflux&select=cred_key,cred_value',
  headers: pgHeaders
});

const credMap = {};
for (const c of (creds || [])) credMap[c.cred_key] = c.cred_value;

if (!credMap.kontoflux_api_key) {
  return [{ json: { error: 'KontoFlux API key not configured. Use add_credential to set it up.' } }];
}
if (!credMap.kontoflux_workspace_id) {
  return [{ json: { error: 'KontoFlux Workspace ID not configured. Use add_credential to set it up.' } }];
}

const API_BASE = 'https://api.kontoflux.io/v1/' + credMap.kontoflux_workspace_id;
const apiHeaders = {
  'Authorization': credMap.kontoflux_api_key
};

// Helper: treat empty strings and dummy values as empty
function isEmpty(v) {
  if (!v) return true;
  const s = String(v).trim().toLowerCase();
  return s === '' || s === 'all' || s === 'none' || s === 'any' || s === 'n/a' || s === 'null' || s === 'undefined';
}

function formatAmount(amount, currency) {
  const sign = amount >= 0 ? '+' : '';
  return sign + amount.toFixed(2) + ' ' + (currency || 'EUR');
}

function formatTransaction(t) {
  let line = formatAmount(t.amount, t.currency);
  if (t.counterpart && t.counterpart.name) line += ' | ' + t.counterpart.name;
  if (t.purpose) line += ' | ' + t.purpose.substring(0, 80);
  if (t.category && t.category.name) line += ' [' + t.category.name + ']';
  if (t.bookingDate) line += ' (' + t.bookingDate + ')';
  return line;
}

// === list_accounts ===
if (action === 'list_accounts') {
  try {
    const resp = await helpers.httpRequest({ method: 'GET', url: API_BASE + '/accounts', headers: apiHeaders });
    const accounts = Array.isArray(resp) ? resp : (resp.data || resp.accounts || [resp]);

    if (accounts.length === 0) return [{ json: { result: 'No bank accounts found.' } }];

    let result = 'Bank Accounts (' + accounts.length + '):\n\n';
    for (const a of accounts) {
      result += '- **' + (a.holderName || 'Unknown') + '**';
      if (a.iban) result += ' | IBAN: ' + a.iban;
      if (a.balance !== undefined) result += ' | Balance: ' + formatAmount(a.balance, a.currency);
      if (a.availableFunds !== undefined) result += ' | Available: ' + formatAmount(a.availableFunds, a.currency);
      if (a.blz) result += ' | BLZ: ' + a.blz;
      result += '\n  ID: ' + (a.id || a._id || 'n/a') + '\n\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list accounts: ' + err.message } }];
  }

// === get_transactions ===
} else if (action === 'get_transactions') {
  try {
    let url = API_BASE;
    if (!isEmpty(input.account_id)) {
      url += '/accounts/' + input.account_id + '/transactions';
    } else {
      url += '/transactions';
    }

    const params = [];
    if (!isEmpty(input.category)) params.push('category=' + encodeURIComponent(input.category));
    if (!isEmpty(input.after)) params.push('bookedAfter=' + encodeURIComponent(input.after));
    if (!isEmpty(input.before)) params.push('bookedBefore=' + encodeURIComponent(input.before));
    const lim = parseInt(input.limit);
    params.push('limit=' + (lim > 0 ? lim : 20));
    params.push('order=desc');
    if (params.length > 0) url += '?' + params.join('&');

    const resp = await helpers.httpRequest({ method: 'GET', url, headers: apiHeaders });
    const transactions = Array.isArray(resp) ? resp : (resp.data || resp.transactions || []);

    if (transactions.length === 0) return [{ json: { result: 'No transactions found.' } }];

    let result = 'Transactions (' + transactions.length + '):\n\n';
    for (const t of transactions) {
      result += '- ' + formatTransaction(t) + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get transactions: ' + err.message } }];
  }

// === search_transactions ===
} else if (action === 'search_transactions') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (search text).' } }];

  try {
    let url = API_BASE + '/transactions/search?query=' + encodeURIComponent(query);
    if (!isEmpty(input.after)) url += '&bookedAfter=' + encodeURIComponent(input.after);
    if (!isEmpty(input.before)) url += '&bookedBefore=' + encodeURIComponent(input.before);
    const searchLim = parseInt(input.limit);
    url += '&limit=' + (searchLim > 0 ? searchLim : 20);

    const resp = await helpers.httpRequest({ method: 'GET', url, headers: apiHeaders });
    const transactions = Array.isArray(resp) ? resp : (resp.data || resp.transactions || []);

    if (transactions.length === 0) return [{ json: { result: 'No transactions found for: ' + query } }];

    let result = 'Search results for "' + query + '" (' + transactions.length + '):\n\n';
    for (const t of transactions) {
      result += '- ' + formatTransaction(t) + '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to search transactions: ' + err.message } }];
  }

// === list_categories ===
} else if (action === 'list_categories') {
  try {
    const resp = await helpers.httpRequest({ method: 'GET', url: API_BASE + '/categories', headers: apiHeaders });
    const categories = Array.isArray(resp) ? resp : (resp.data || resp.categories || []);

    if (categories.length === 0) return [{ json: { result: 'No categories found.' } }];

    let result = 'Transaction Categories:\n\n';
    for (const cat of categories) {
      result += '- **' + cat.name + '** (ID: ' + (cat.id || cat._id) + ')';
      if (cat.children && cat.children.length > 0) {
        result += '\n  Sub: ' + cat.children.map(c => c.name).join(', ');
      }
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list categories: ' + err.message } }];
  }

// === check_scope ===
} else if (action === 'check_scope') {
  try {
    const resp = await helpers.httpRequest({ method: 'GET', url: API_BASE + '/key/scope', headers: apiHeaders });
    return [{ json: { result: 'API Key Scope:\n' + JSON.stringify(resp, null, 2) } }];
  } catch (err) {
    return [{ json: { error: 'Failed to check scope: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use list_accounts, get_transactions, search_transactions, list_categories, or check_scope.' } }];
}
